('List countries that have at least one city.', 'SELECT name FROM countries c WHERE EXISTS (SELECT 1 FROM cities ci WHERE ci.country_id = c.id)', 'medium', 'Correlated Subqueries', 'Advanced', ' with the outer country id.'),
('Find countries whose population is above the average for their region.', 'SELECT name FROM countries c1 WHERE population > (SELECT AVG(population) FROM countries c2 WHERE c2.region = c1.region)', 'hard', 'Correlated Subqueries', 'Advanced', 'The subquery must match the outer row region.'),
('Find cities whose population is above the average city population in their country.', 'SELECT name FROM cities c1 WHERE population > (SELECT AVG(population) FROM cities c2 WHERE c2.country_id = c1.country_id)', 'hard', 'Correlated Subqueries', 'Advanced', 'Correlate by country_id.'),
('List each country with its largest city population.', 'SELECT c.name, (SELECT MAX(ci.population) FROM cities ci WHERE ci.country_id = c.id) FROM countries c', 'hard', 'Correlated Subqueries', 'Advanced', ' subquery in the SELECT list.'),
('List each state with its total city population.', 'SELECT s.name, (SELECT SUM(ci.population) FROM cities ci WHERE ci.state_id = s.id) FROM states s', 'hard', 'Correlated Subqueries', 'Advanced', 'Subquery sums cities for each state.'),
('Find the largest city in each country.', 'SELECT ci.name FROM cities ci WHERE ci.population = (SELECT MAX(ci2.population) FROM cities ci2 WHERE ci2.country_id = ci.country_id)', 'hard', 'Correlated Subqueries', 'Advanced', 'Compare each city to max population in its country.'),
('Find countries whose GDP is greater than the average GDP of their subregion.', 'SELECT name FROM countries c1 WHERE gdp > (SELECT AVG(gdp) FROM countries c2 WHERE c2.subregion = c1.subregion AND c2.gdp IS NOT NULL)', 'hard', 'Correlated Subqueries', 'Advanced', 'Correlate by subregion and ignore NULL GDP.');
